/* CarBoxCars: dropdown sources + (brand, model, year) -> core-6 specs lookup.
   Years are validated to CarBox's 2010+ policy by the caller; lookup itself
   just returns the best-matching generation for whatever year it is given. */
window.CarBoxCars = (function () {
  var DB = window.CARBOX_CARS || { brands: [], models: {}, data: {} };
  function brands() { return DB.brands.slice(); }
  function models(brand) { return (DB.models[brand] || []).slice(); }
  function hasBrand(b) { return DB.models.hasOwnProperty(b); }
  function hasModel(b, m) { return (DB.models[b] || []).indexOf(m) !== -1; }
  /* best entry for a model at a given year:
       1) generations whose [yearStart,yearEnd] contains the year — take the
          first (entries are authored base-trim-first);
       2) otherwise the generation whose range is nearest the year. */
  function lookup(brand, model, year) {
    var rows = (DB.data[brand] || []).filter(function (e) { return e.model === model; });
    if (!rows.length) return null;
    var y = parseInt(year, 10);
    var inRange = rows.filter(function (e) { return y >= e.yearStart && y <= e.yearEnd; });
    var pick;
    if (inRange.length) {
      pick = inRange[0];
    } else {
      var best = null, bestD = Infinity;
      rows.forEach(function (e) {
        var d = y < e.yearStart ? e.yearStart - y : y - e.yearEnd;
        if (d < bestD) { bestD = d; best = e; }
      });
      pick = best;
    }
    return {
      specs: {
        engine: pick.specs.engine, horsepower: pick.specs.horsepower,
        torque: pick.specs.torque, transmission: pick.specs.transmission,
        drivetrain: pick.specs.drivetrain, accel: pick.specs.accel
      },
      trim: pick.trim, generation: pick.generation,
      yearStart: pick.yearStart, yearEnd: pick.yearEnd,
      exact: (y >= pick.yearStart && y <= pick.yearEnd)
    };
  }
  return { brands: brands, models: models, hasBrand: hasBrand, hasModel: hasModel, lookup: lookup };
})();
